module RefModule(  
    input wire clk,  
    input wire reset,  
    output reg [7:0] count  
);  
  wire _tap_clk = clk & {1{1'b1}};

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            count <= 8'b00000000;  
        end else begin  
            count <= count + 1;  
        end  
    end  
endmodule
